  code: "NOT_FOUND" | "VALIDATION_ERROR";
  message: string;
}

export type ServiceResult<T> =
  | { success: true; data: T }
  | { success: false; error: ServiceError };
```

That is all. The return-shape interfaces (`ProductListResult`, `ProductDetailResult`, `OrderListResult`, `EnrichedOrder`, `EnrichedOrderItem`, filter param interfaces) are local to their respective service files and do not need to be in `types.ts`. They are implementation details of the service layer.

